    if (!expanded.url) {
      throw new Error(`MCP server "${name}" requires url for type "${serverType}"`);
    }
    const config2 = {
      type: "remote",
      url: expanded.url,
      enabled: true
    };
    if (expanded.headers && Object.keys(expanded.headers).length > 0) {
      config2.headers = expanded.headers;
    }
    return config2;
