  if (shouldStopForStagnation({ sessionID, incompleteCount, progressUpdate })) {
    return;
  }
  startCountdown({
    ctx,
    sessionID,
    incompleteCount,
    total: todos.length,
    resolvedInfo,
    backgroundManager,
    skipAgents,
    sessionStateStore,
    isContinuationStopped
  });
