import * as crypto2 from "crypto";
import * as fs12 from "fs";
import * as path9 from "path";
init_logger();
var EXACT_SEMVER_REGEX2 = /^\d+\.\d+\.\d+(-[0-9A-Za-z-]+(\.[0-9A-Za-z-]+)*)?(\+[0-9A-Za-z-]+(\.[0-9A-Za-z-]+)*)?$/;
