import { readFileSync as readFileSync38 } from "fs";
function extractSkillTemplate(skill) {
  if (skill.path) {
    const content = readFileSync38(skill.path, "utf-8");
    const { body } = parseFrontmatter(content);
    return body.trim();
  }
  return skill.definition.template || "";
}
