var POLL_INTERVAL_MS = 1000;
var MIN_STABILITY_TIME_MS = 1e4;
var STABILITY_POLLS_REQUIRED = 3;
var WAIT_FOR_SESSION_INTERVAL_MS = 100;
var WAIT_FOR_SESSION_TIMEOUT_MS = 30000;
